export default function () {
  const headerTitle = document.createElement("div");
  headerTitle.classList.add("header__title");
  headerTitle.innerHTML = "English for kids";

  const modeText = document.createElement("div");
  modeText.classList.add("mode-text");
  modeText.innerHTML = "Game mode";

  const modeBtnLabel = document.createElement("label");
  modeBtnLabel.classList.add("switch");
  const modeBtnInput = document.createElement("input");
  modeBtnInput.type = "checkbox";
  const modeBtnSpan = document.createElement("span");
  modeBtnSpan.classList.add("slider");
  modeBtnSpan.classList.add("round");
  modeBtnLabel.append(modeBtnInput);
  modeBtnLabel.append(modeBtnSpan);

  const header = document.createElement("header");
  header.classList.add("header");
  header.append(headerTitle);
  header.append(modeText);
  header.append(modeBtnLabel);

  const main = document.createElement("main");
  main.classList.add("main");
  for (let i = 0; i < 8; i += 1) {
    const card = document.createElement("div");
    card.classList.add("card");
    main.append(card);
  }

  const wrapper = document.createElement("div");
  wrapper.classList.add("wrapper");
  wrapper.append(header);
  wrapper.append(main);

  document.body.append(wrapper);
}