import cards from "./cards";

export default class Menu {
  // create menu and menu button with event listener
  getMenu() {
    this.displayMenu();
    this.displayButton();
    this.setButton();
    this.setMenu();
  }

  displayMenu() {
    // set menu header
    const menuHeader = document.createElement("div");
    menuHeader.classList.add("menu__header");
    // set menu title
    const menuTitle = document.createElement("div");
    menuTitle.classList.add("header__title");
    menuTitle.innerHTML = "English for kids";
    menuHeader.append(menuTitle);
    // set menu items list
    const menuUl = document.createElement("ul");
    cards[0].forEach((e) => {
      const menuItem = document.createElement("div");
      menuItem.classList.add("menu__item");
      menuItem.innerHTML = e;
      //! TODO set cards depends on e
      // menuItem.addEventListener("click", () => {

      // })
      menuUl.append(menuItem);
    });
    // set menu block, add header, title and items list
    const nav = document.createElement("nav");
    nav.classList.add("menu");
    nav.append(menuHeader);
    nav.append(menuUl);
    // append menu to page
    const wrapper = document.querySelector(".wrapper");
    wrapper.prepend(nav);
  }

  displayButton() {
    // create menu button block
    const menuBtn = document.createElement("div");
    menuBtn.classList.add("menu__button");
    // create menu button bars
    const bars = [1, 2, 3];
    bars.forEach((e) => {
      const bar = document.createElement("div");
      bar.classList.add(`menu__button--bar${e}`);
      menuBtn.append(bar);
    });
    // append menu button to page
    const header = document.querySelector(".header");
    header.prepend(menuBtn);
  }

  setButton() {
    // use closure to store menuStatus
    let menuStatus = "close";
    // set menu button (add event listener)
    function setButton() {
      const header = document.querySelector(".header");
      const menuBtn = document.querySelector(".menu__button");
      const menu = document.querySelector(".menu");
      const menuHeader = document.querySelector(".menu__header");

      menuBtn.addEventListener("click", function toggleMenu(e) {
        e.stopPropagation();
        menuBtn.classList.toggle("change-menu-btn");

        function shadeBackground(n) {
          setTimeout(() => {
            if (n === 1) {
              const shadeDiv = document.createElement("div");
              shadeDiv.classList.add("menu__shade-div");
              document.body.prepend(shadeDiv);
            } else {
              document.querySelector(".menu__shade-div").remove();
            }
          }, 300);
        }

        if (menuStatus === "close") {
          shadeBackground(1);
          menu.classList.toggle("menu--visible");
          setTimeout(() => {
            menuHeader.append(menuBtn);
          }, 400);
          menuStatus = "open";
        } else {
          shadeBackground(0);
          setTimeout(() => {
            menu.classList.toggle("menu--visible");
          }, 150);
          setTimeout(() => {
            header.prepend(menuBtn);
          }, 300);
          menuStatus = "close";
        }
      });
    }
    return setButton();
  }

  setMenu() {
    const menuBtn = document.querySelector(".menu__button");
    const menu = document.querySelector(".menu");
    // catch click anywhere on page and emulate click on menu button
    document.body.addEventListener("click", () => {
      if (menu.classList.contains("menu--visible")) {
        menuBtn.click();
      }
    });
    // catch click on menu and stop propagation
    menu.addEventListener("click", (e) => {
      e.stopPropagation();
    });
  }
}
